// src/app.js
const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

// src/server.js
const app = require('./app');
const port = process.env.PORT || 3000;

module.exports = app;

// src/modules/projects/routes.js
const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/:projectId', async (req, res) => {
  try {
    const project = await projectsService.getProjectById(req.params.projectId);
    if (!project) {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    }
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name must be provided');
  }
  try {
    const project = await projectsService.createProject(name);
    res.status(201).json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');

let projectsStore = [];

async function createProject(name) {
  const project = { id: randomUUID(), name };
  projectsStore.push(project);
  return project;
}

async function getProjectById(id) {
  return projectsStore.find(project => project.id === id);
}

module.exports = {
  createProject,
  getProjectById,
};
module.exports.getAllProjects = async function getAllProjectsBridge() { return Array.isArray(projectsStore) ? [...projectsStore] : []; };

const router = require('express').Router();
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');
router.get('/', async (req, res) => {
  const status = typeof req.query?.status === 'string' ? req.query.status : undefined;
  const tasks = await tasksService.getAllTasks(req.params.projectId, status);
  return res.json({ tasks });
});
router.post('/', async (req, res) => {
  const title = String(req.body?.title || "").trim();
  if (!title) return sendError(res, 400, 'BAD_REQUEST', 'Task title is required');
  const task = await tasksService.createTask(req.params.projectId, title);
  return res.status(201).json({ task });
});
router.patch('/:taskId', async (req, res) => {
  const status = String(req.body?.status || '').trim();
  if (status !== 'todo' && status !== 'done') return sendError(res, 400, 'INVALID_STATUS', 'Status must be todo or done');
  const task = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
  if (!task) return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  return res.json({ task });
});
module.exports = router;

// src/modules/members/routes.js
const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'Both userId and role must be provided');
  }
  try {
    const member = await membersService.addMember(req.params.projectId, userId, role);
    res.status(201).json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const { sendError } = require('../../lib/errors');

let membersStore = [];

async function createMember(projectId, userId, role) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }

  const member = { id: randomUUID(), projectId, userId, role };
  membersStore.push(member);
  return member;
}

module.exports = {
  createMember,
};
module.exports.addMember = module.exports.createMember;

// src/modules/comments/routes.js
const express = require('express');
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_MESSAGE', 'Message must be provided');
  }

  try {
    const comment = await commentsService.createComment(req.params.projectId, req.params.taskId, message);
    res.status(201).json({ comment });
  } catch (error) {
    sendError(res, error.statusCode || 500, error.code || 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;

// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');
const tasksService = require('../tasks/service');
const { sendError } = require('../../lib/errors');

let commentsStore = [];

async function createComment(projectId, taskId, message) {
  const task = await tasksService.getTaskById(taskId);
  if (!task || task.projectId !== projectId) {
    return null;
  }

  const comment = { id: randomUUID(), taskId, message };
  commentsStore.push(comment);
  return comment;
}

module.exports = {
  createComment,
};

// src/lib/errors.js
function sendError(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
}

module.exports = {
  sendError,
};

const { randomUUID } = require('crypto');

function generateId() {
  return randomUUID();
}

module.exports = { generateId };
